import java.util.*;
class Solution {
  static int[] solve(int[] arr, int target) {
    Map<Integer,Integer> seen = new HashMap<>();
    for (int i=0;i<arr.length;i++) {
      int need = target - arr[i];
      if (seen.containsKey(need)) return new int[]{seen.get(need), i};
      seen.put(arr[i], i);
    }
    return null;
  }
}

