// Caso: Rotar arreglo k | Nivel: Intermedio | Categoría: Arrays

class Solution {
  static int[] solve(int[] arr, int k) {
    int n = arr.length;
    if (n == 0) return new int[0];
    int r = ((k % n) + n) % n;
    int[] out = new int[n];
    for (int i=0;i<n;i++) out[(i + r) % n] = arr[i];
    return out;
  }
}

