import java.util.Arrays;
class Solution {
  static int[] solve(int[] arr) {
    int[] a = Arrays.copyOf(arr, arr.length);
    for (int i=0;i<a.length;i++) {
      for (int j=0;j<a.length-1-i;j++) {
        if (a[j] > a[j+1]) { int t=a[j]; a[j]=a[j+1]; a[j+1]=t; }
      }
    }
    return a;
  }
}

