import java.util.*;
class Solution {
  static int[] solve(int[] arr) {
    Set<Integer> seen = new LinkedHashSet<>();
    for (int x : arr) seen.add(x);
    int[] out = new int[seen.size()];
    int i=0; for (int x : seen) out[i++] = x;
    return out;
  }
}

