// Maven: com.opencsv:opencsv
import java.io.*;
import com.opencsv.*;

class Solution {
  static void solve(String inputPath, String outputPath) throws Exception {
    try (CSVReader r = new CSVReader(new InputStreamReader(new FileInputStream(inputPath), "UTF-8"));
         CSVWriter w = new CSVWriter(new OutputStreamWriter(new FileOutputStream(outputPath), "UTF-8"))) {

      String[] header = r.readNext();
      if (header == null) return;
      w.writeNext(header);

      String[] row;
      while ((row = r.readNext()) != null) {
        for (int i=0;i<header.length;i++){
          if ("Email".equalsIgnoreCase(header[i]) && i < row.length && row[i]!=null){
            row[i] = row[i].trim().toLowerCase();
          }
        }
        w.writeNext(row);
      }
    }
  }
}

