import java.net.URI;
import java.net.http.*;
import java.time.Duration;

class Solution {
  static void solve() throws Exception {
    var client = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(5)).build();
    var getReq = HttpRequest.newBuilder(URI.create("http://localhost:3000/api/items"))
      .timeout(Duration.ofSeconds(5)).GET().build();
    var items = client.send(getReq, HttpResponse.BodyHandlers.ofString()).body();

    var postReq = HttpRequest.newBuilder(URI.create("http://localhost:3000/api/items"))
      .timeout(Duration.ofSeconds(5))
      .header("Content-Type","application/json")
      .POST(HttpRequest.BodyPublishers.ofString("{"name":"Item","qty":1}"))
      .build();
    var created = client.send(postReq, HttpResponse.BodyHandlers.ofString()).body();

    System.out.println(items);
    System.out.println(created);
  }
}

