// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
import java.util.*;

class Solution {
  static List<String> bfs(Map<String,List<String>> g, String start){
    var q = new ArrayDeque<String>();
    var seen = new HashSet<String>();
    var out = new ArrayList<String>();
    q.add(start); seen.add(start);
    while(!q.isEmpty()){
      var v = q.removeFirst(); out.add(v);
      for (var n: g.getOrDefault(v, List.of())){
        if (seen.add(n)) q.add(n);
      }
    }
    return out;
  }
  static List<String> dfs(Map<String,List<String>> g, String start){
    var out = new ArrayList<String>();
    var seen = new HashSet<String>();
    visit(g,start,seen,out);
    return out;
  }
  static void visit(Map<String,List<String>> g, String v, Set<String> seen, List<String> out){
    seen.add(v); out.add(v);
    for (var n: g.getOrDefault(v, List.of())){
      if (!seen.contains(n)) visit(g,n,seen,out);
    }
  }
}

