// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// Java: lectura básica por stdin (WASD + q) (requiere Enter)
import java.io.*;

class Solution {
  static void solve() throws Exception {
    System.out.println("Escribe una tecla y Enter (w/a/s/d, q):");
    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    while (true) {
      String line = br.readLine();
      if (line == null || line.isEmpty()) continue;
      char k = Character.toLowerCase(line.charAt(0));
      if (k == 'q') break;
      if (k == 'w') System.out.println("Mover: arriba");
      if (k == 's') System.out.println("Mover: abajo");
      if (k == 'a') System.out.println("Mover: izquierda");
      if (k == 'd') System.out.println("Mover: derecha");
    }
  }
}

